const fs = require('fs');
const path = require('path');

// Async with callbacks
const inputPath = path.join(__dirname, 'input.txt');
const outputPath = path.join(__dirname, 'output.txt');

fs.readFile(inputPath, 'utf8', (err, data) => {
  if (err) { console.error('Read error:', err); return; }
  const modified = data + '\nAppended line!';
  fs.writeFile(outputPath, modified, 'utf8', (err) => {
    if (err) console.error('Write error:', err);
    else console.log('File written successfully!');
  });
});

// Better: using fs.promises (async/await)
async function processFile() {
  const data = await fs.promises.readFile(inputPath, 'utf8');
  const modified = data + '\nAppended line!';
  await fs.promises.writeFile(outputPath, modified, 'utf8');
  console.log('Done!');
}

processFile().catch(console.error);

