const express = require('express');
const app = express();

app.use(express.json());

// 1. Logger Middleware
function logger(req, res, next) {
  const start = Date.now();
  res.on('finish', () => {
    const duration = Date.now() - start;
    console.log(`${req.method} ${req.url} ${res.statusCode} - ${duration}ms`);
  });
  next();
}

// 2. Auth Middleware (JWT-like)
function authenticate(req, res, next) {
  const authHeader = req.headers.authorization;
  if (!authHeader?.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  const token = authHeader.split(' ')[1];
  // In real app: verify JWT token
  if (token !== 'valid-token') {
    return res.status(403).json({ error: 'Invalid token' });
  }
  req.user = { id: 1, name: 'Alice' }; // attach user to request
  next();
}

// 3. Error Handler Middleware (must have 4 params)
function errorHandler(err, req, res, next) {
  console.error(err.stack);
  res.status(err.status || 500).json({
    error: err.message || 'Internal Server Error'
  });
}

app.use(logger);

app.get('/public', (req, res) => res.json({ msg: 'Public route' }));

app.get('/private', authenticate, (req, res) => {
  res.json({ msg: `Hello ${req.user.name}` });
});

app.get('/error', (req, res, next) => {
  next(new Error('Something broke!'));
});

app.use(errorHandler); // Must be last!

app.listen(3000);

