const fs = require('fs');
const readline = require('readline');
const path = require('path');

async function processLargeFile(inputPath, outputPath) {
  const readStream = fs.createReadStream(inputPath, { encoding: 'utf8' });
  const writeStream = fs.createWriteStream(outputPath);
  const rl = readline.createInterface({ input: readStream });

  let lineCount = 0;

  for await (const line of rl) {
    lineCount++;
    // Process: transform CSV line (e.g., uppercase)
    const processed = line.toUpperCase();
    writeStream.write(processed + '\n');
  }

  writeStream.end();
  console.log(`Processed ${lineCount} lines`);
}

// Pipeline (cleaner with error handling)
const { pipeline } = require('stream/promises');
const { Transform } = require('stream');

async function pipelineExample(input, output) {
  const upper = new Transform({
    transform(chunk, encoding, callback) {
      callback(null, chunk.toString().toUpperCase());
    }
  });

  await pipeline(
    fs.createReadStream(input),
    upper,
    fs.createWriteStream(output)
  );
  console.log('Pipeline done');
}

processLargeFile('input.csv', 'output.csv').catch(console.error);

