const EventEmitter = require('events');

class OrderProcessor extends EventEmitter {
  constructor() {
    super();
    this.orders = [];
  }

  async processOrder(order) {
    this.emit('processing', order);
    try {
      // Simulate async processing (DB save, payment, etc.)
      await new Promise(resolve => setTimeout(resolve, 100));
      if (!order.userId) throw new Error('User ID required');
      if (order.amount <= 0) throw new Error('Amount must be positive');

      order.id = Date.now();
      order.status = 'confirmed';
      this.orders.push(order);

      this.emit('success', order);
      return order;
    } catch (err) {
      this.emit('error', err);
      throw err;
    }
  }

  getOrders() { return this.orders; }
}

const processor = new OrderProcessor();
processor.on('processing', o => console.log('Processing:', o));
processor.on('success', o => console.log('Order confirmed:', o.id));
processor.on('error', e => console.error('Failed:', e.message));

processor.processOrder({ userId: 1, amount: 99.99, item: 'Laptop' });
processor.processOrder({ userId: null, amount: 50 }); // Will emit error

